"""Signing tests for orchestkit-hook-contract (M141-4, #1805).

Two layers, matching the npm side:
  1. Vector-driven: loads every JSON in ``../hook-contract/test-vectors/signing/``
     and asserts. These are the cross-language conformance contract.
  2. API-level: covers programmer-error raises, sign() round-trip, weak-secret
     callback, and key-rotation acceptance.
"""

from __future__ import annotations

import base64
import binascii
import json
from pathlib import Path
from typing import Any

import pytest

from orchestkit_hook_contract.signing import (
    HOOK_SIGNATURE_HEADER,
    MIN_SECRET_BYTES,
    sign,
    verify,
)

# Vectors live in the npm package's tree — symlinks are messy across npm/PyPI
# packaging, so we resolve the path at test time.
VECTORS_DIR = Path(__file__).resolve().parents[2] / "hook-contract" / "test-vectors" / "signing"


def _load_vectors() -> list[dict[str, Any]]:
    files = sorted(VECTORS_DIR.glob("*.json"))
    return [json.loads(f.read_text()) for f in files]


VECTORS = _load_vectors()


def test_loaded_required_vectors() -> None:
    assert len(VECTORS) >= 13, f"expected ≥13 vectors, found {len(VECTORS)}"


@pytest.mark.parametrize("vector", VECTORS, ids=lambda v: v["name"])
def test_vector(vector: dict[str, Any]) -> None:
    secret = binascii.unhexlify(vector["secret_hex"])
    body = base64.b64decode(vector["body_b64"])
    header = None if vector["header"] == "" else vector["header"]

    result = verify(
        header,
        body,
        secret,
        now=vector["now"],
        tolerance_sec=vector["tolerance_sec"],
    )

    assert result.valid is vector["expected"]["valid"], (
        f"{vector['name']}: valid mismatch — got {result.valid}, expected {vector['expected']['valid']}"
    )
    assert result.reason == vector["expected"]["reason"], (
        f"{vector['name']}: reason mismatch — got {result.reason!r}, expected {vector['expected']['reason']!r}"
    )


# ─── API surface ──────────────────────────────────────────────────────────


SECRET = bytes.fromhex("00112233445566778899aabbccddeeff00112233445566778899aabbccddeeff")
BODY = b'{"event":"PreToolUse"}'


def test_header_name_constant() -> None:
    assert HOOK_SIGNATURE_HEADER == "X-CC-Hooks-Signature"


def test_min_secret_bytes_exposed() -> None:
    assert MIN_SECRET_BYTES == 32


def test_sign_verify_round_trip() -> None:
    t = 1_731_000_000
    header = sign(BODY, SECRET, timestamp=t)
    assert header.startswith(f"t={t},v1=")
    assert len(header.split("v1=")[1]) == 64

    result = verify(header, BODY, SECRET, now=t)
    assert result.valid is True
    assert result.reason == "ok"


@pytest.mark.parametrize("header", [None, ""])
def test_missing_header(header: str | None) -> None:
    assert verify(header, BODY, SECRET).reason == "missing_header"


@pytest.mark.parametrize(
    "header",
    [
        "",
        ",",
        "=",
        "t=,v1=" + "a" * 64,
        "t=abc,v1=" + "a" * 64,
        "t=1731000000,v1=",
        "t=1731000000,v1=zzzz",
        "t=1731000000,t=1731000000,v1=" + "a" * 64,
        "t=1731000000,v1=" + "a" * 64 + ",v1=" + "b" * 64,
        "t=1731000000,unknown=" + "a" * 64,
        " t=1731000000,v1=" + "a" * 64,
    ],
)
def test_malformed_inputs_never_raise(header: str) -> None:
    result = verify(header, BODY, SECRET, now=1_731_000_000)
    assert result.valid is False
    assert result.reason in {"malformed_header", "missing_header", "signature_mismatch"}


@pytest.mark.parametrize(
    "kwargs,match",
    [
        ({"timestamp": -1}, "non-negative"),
        ({"scheme": "v"}, "scheme"),
        ({"scheme": "V1"}, "scheme"),
    ],
)
def test_sign_rejects_invalid_args(kwargs: dict[str, Any], match: str) -> None:
    with pytest.raises(TypeError, match=match):
        sign(BODY, SECRET, **kwargs)


def test_verify_rejects_non_bytes_body() -> None:
    with pytest.raises(TypeError, match="body"):
        verify("t=1,v1=" + "a" * 64, "not bytes", SECRET)  # type: ignore[arg-type]


def test_verify_rejects_none_secret() -> None:
    with pytest.raises(TypeError, match="secret"):
        verify("t=1,v1=" + "a" * 64, BODY, None)  # type: ignore[arg-type]


def test_rotation_accepts_any_matching_secret() -> None:
    t = 1_731_000_000
    old_secret = bytes([0xAA] * 32)
    new_secret = bytes([0xBB] * 32)
    header_old = sign(BODY, old_secret, timestamp=t)

    result = verify(header_old, BODY, [new_secret, old_secret], now=t)
    assert result.valid is True
    assert result.reason == "ok"


def test_weak_secret_warning_fires() -> None:
    seen: list[str] = []
    short_secret = bytes([0xAA] * 16)
    header = sign(BODY, short_secret, timestamp=1_731_000_000)
    result = verify(
        header,
        BODY,
        short_secret,
        now=1_731_000_000,
        on_warning=lambda r: seen.append(r),
    )
    assert result.valid is True
    assert result.reason == "ok"
    assert seen == ["weak_secret"]


def test_weak_secret_does_not_fire_on_strong_secret() -> None:
    seen: list[str] = []
    verify(
        sign(BODY, SECRET),
        BODY,
        SECRET,
        on_warning=lambda r: seen.append(r),
    )
    assert seen == []


def test_weak_secret_does_not_fire_on_malformed_header() -> None:
    """Info-disclosure tightening: malformed headers MUST NOT trigger the warning."""
    seen: list[str] = []
    short_secret = bytes([0xAA] * 16)
    verify("garbage", BODY, short_secret, on_warning=lambda r: seen.append(r))
    assert seen == []


def test_multi_scheme_header_any_match_passes() -> None:
    t = 1_731_000_000
    secret_a = bytes([0xAA] * 32)
    secret_b = bytes([0xBB] * 32)
    h_a = sign(BODY, secret_a, timestamp=t, scheme="v1")
    h_b = sign(BODY, secret_b, timestamp=t, scheme="v2")
    combined = h_a + "," + h_b.split(",")[1]

    assert verify(combined, BODY, secret_b, now=t).reason == "ok"
    assert verify(combined, BODY, secret_a, now=t).reason == "ok"


def test_header_length_dos_cap() -> None:
    """Headers above 8192 bytes return malformed_header — DoS guardrail."""
    t = 1_731_000_000
    header = f"t={t}"
    i = 100
    while len(header) <= 8192:
        header += f",v{i}={'a' * 64}"
        i += 1
    assert len(header) > 8192

    result = verify(header, BODY, SECRET, now=t)
    assert result.reason == "malformed_header"


def test_timestamp_more_than_10_digits_returns_stale() -> None:
    """Cross-language parity: 11+ digits returns stale, not malformed."""
    too_long = "1" + "0" * 15
    result = verify(f"t={too_long},v1=" + "a" * 64, BODY, SECRET)
    assert result.reason == "stale"
